import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = () => {
  const location = useLocation();
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      if (window.scrollY > 50) {
        setIsScrolled(true);
      } else {
        setIsScrolled(false);
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { path: '/', label: 'Home' },
    { path: '/politicians', label: 'Politicians' },
    { path: '/promises', label: 'Promises' },
    { path: '/feedback', label: 'Feedback' },
    { path: '/news', label: 'News' },
    { path: '/notifications', label: 'Notifications' },
  ];

  const isActive = (path) => {
    if (path === '/' && location.pathname === '/') return true;
    if (path !== '/' && location.pathname.startsWith(path)) return true;
    return location.pathname === path;
  };

  return (
    <nav 
      className={`
        fixed top-0 left-0 right-0 z-50 transition-all duration-500
        ${isScrolled 
          ? 'bg-white shadow-lg border-b border-gray-200' 
          : 'bg-transparent'
        }
      `}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16 lg:h-20">
          {/* Logo */}
          <Link 
            to="/" 
            className={`
              text-2xl font-bold tracking-tight transition-all duration-300
              ${isScrolled 
                ? 'text-gray-900' 
                : 'text-white'
              }
            `}
          >
            <span>Janaya</span>
            <span className={`
              transition-all duration-300
              ${isScrolled 
                ? 'text-blue-600' 
                : 'text-blue-400'
              }
            `}>360</span>
          </Link>

          {/* Desktop Navigation */}
          <div className="hidden lg:flex items-center space-x-1">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`
                  px-4 py-2 rounded-lg text-sm font-medium transition-all duration-300
                  ${isActive(link.path)
                    ? isScrolled
                      ? 'bg-blue-600 text-white'
                      : 'bg-white/20 text-white backdrop-blur-sm'
                    : isScrolled
                      ? 'text-gray-600 hover:bg-blue-50 hover:text-blue-600'
                      : 'text-white/90 hover:bg-white/10 hover:text-white'
                  }
                `}
              >
                {link.label}
              </Link>
            ))}
          </div>

          {/* Auth Buttons - Desktop */}
          <div className="hidden lg:flex items-center space-x-4">
            <Link
              to="/login"
              className={`
                px-5 py-2 text-sm font-medium transition-all duration-300 rounded-lg
                ${isScrolled
                  ? 'text-gray-600 border border-gray-300 hover:border-blue-600 hover:text-blue-600'
                  : 'text-white border border-white/50 hover:border-white hover:bg-white/10'
                }
              `}
            >
              Sign In
            </Link>
            <Link
              to="/register"
              className={`
                px-5 py-2 text-sm font-medium transition-all duration-300 rounded-lg font-semibold
                ${isScrolled
                  ? 'bg-blue-600 text-white hover:bg-blue-500 shadow-sm'
                  : 'bg-white text-blue-600 hover:bg-blue-50'
                }
              `}
            >
              Get Started
            </Link>
          </div>

          {/* Mobile Menu Button */}
          <button
            onClick={() => setIsMenuOpen(!isMenuOpen)}
            className={`
              lg:hidden p-2 rounded-lg transition-all duration-300
              ${isScrolled
                ? 'hover:bg-gray-100'
                : 'hover:bg-white/10'
              }
            `}
            aria-expanded="false"
          >
            <span className="sr-only">Open main menu</span>
            <svg 
              className={`
                h-6 w-6 transition-all duration-300
                ${isScrolled ? 'text-gray-600' : 'text-white'}
              `} 
              fill="none" 
              viewBox="0 0 24 24" 
              stroke="currentColor"
            >
              {!isMenuOpen ? (
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
              ) : (
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              )}
            </svg>
          </button>
        </div>

        {/* Mobile Menu */}
        <div 
          className={`
            lg:hidden overflow-hidden transition-all duration-500
            ${isMenuOpen ? 'max-h-96 opacity-100' : 'max-h-0 opacity-0'}
          `}
        >
          <div className={`
            px-2 pt-2 pb-4 space-y-1 rounded-lg mt-2
            ${isScrolled
              ? 'bg-white'
              : 'bg-black/50 backdrop-blur-md'
            }
          `}>
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                onClick={() => setIsMenuOpen(false)}
                className={`
                  block px-4 py-2 rounded-lg text-base font-medium transition-all duration-300
                  ${isActive(link.path)
                    ? isScrolled
                      ? 'bg-blue-600 text-white'
                      : 'bg-white/20 text-white'
                    : isScrolled
                      ? 'text-gray-600 hover:bg-blue-50 hover:text-blue-600'
                      : 'text-white/90 hover:bg-white/10 hover:text-white'
                  }
                `}
              >
                {link.label}
              </Link>
            ))}
            
            {/* Mobile Auth Buttons */}
            <div className="pt-4 space-y-2">
              <Link
                to="/login"
                onClick={() => setIsMenuOpen(false)}
                className={`
                  block w-full text-center px-4 py-2 text-sm font-medium rounded-lg transition-all duration-300
                  ${isScrolled
                    ? 'text-gray-600 border border-gray-300 hover:border-blue-600 hover:text-blue-600'
                    : 'text-white border border-white/50 hover:border-white hover:bg-white/10'
                  }
                `}
              >
                Sign In
              </Link>
              <Link
                to="/register"
                onClick={() => setIsMenuOpen(false)}
                className={`
                  block w-full text-center px-4 py-2 text-sm font-medium rounded-lg transition-all duration-300 font-semibold
                  ${isScrolled
                    ? 'bg-blue-600 text-white hover:bg-blue-500'
                    : 'bg-white text-blue-600 hover:bg-blue-50'
                  }
                `}
              >
                Get Started
              </Link>
            </div>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
